import React, { useEffect, useState } from "react";
import { Table, Button, Input, Space, Tag, Modal, Skeleton } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { 
  FileText, 
  Plus, 
  Search, 
  Edit3, 
  Trash2, 
  Activity, 
  ShieldCheck,
  ExternalLink,
  ChevronRight,
  Eye,
  Activity as PulseIcon,
  ShoppingBag
} from "lucide-react";
import { Link } from "react-router-dom";
import { getHealthAdvices, deleteHealthAdvice } from "../../features/healthAdvice/healthAdviceSlice";

const HealthAdviceList = () => {
    const dispatch = useDispatch();
    const [searchText, setSearchText] = useState("");

    useEffect(() => {
        dispatch(getHealthAdvices());
    }, [dispatch]);

    const { healthAdvices, isLoading } = useSelector((state) => state.healthAdvice || { healthAdvices: [] });

    const handleDelete = (id) => {
        Modal.confirm({
            title: 'Terminate Medical Protocol?',
            content: 'This will permanently remove this condition guide from the public encyclopedia. Are you sure?',
            okText: 'Terminate',
            okType: 'danger',
            cancelText: 'Cancel',
            centered: true,
            onOk: () => {
                dispatch(deleteHealthAdvice(id));
            }
        });
    };

    const columns = [
        {
            title: () => (
                <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-black tracking-widest text-slate-400 uppercase">Archive</span>
                    <span className="text-[11px] font-black text-slate-900 border-b-2 border-teal-500 pb-1 w-fit">MEDIA UNIT</span>
                </div>
            ),
            dataIndex: "image",
            width: 140,
            render: (image, record) => (
                <div className="relative group overflow-visible">
                    <div className="w-24 h-16 rounded-2xl bg-slate-100 overflow-hidden border-2 border-white shadow-sm transition-all group-hover:scale-105 group-hover:rotate-2 group-hover:shadow-xl">
                        {image?.url || image?.secure_url ? (
                            <img 
                                src={image.url || image.secure_url} 
                                alt={record.conditionName} 
                                className="w-full h-full object-cover"
                            />
                        ) : (
                            <div className="w-full h-full flex items-center justify-center text-slate-300 bg-slate-50">
                                <PulseIcon size={24} strokeWidth={1.5} />
                            </div>
                        )}
                    </div>
                </div>
            ),
        },
        {
            title: () => (
                <div className="flex flex-col gap-1 w-full whitespace-nowrap">
                    <span className="text-[10px] font-black tracking-widest text-slate-400 uppercase">Classification</span>
                    <span className="text-[11px] font-black text-slate-900 border-b-2 border-teal-500 pb-1 w-fit">CLINICAL CONDITION</span>
                </div>
            ),
            dataIndex: "conditionName",
            width: 240,
            render: (text, record) => (
                <div className="space-y-1.5 whitespace-nowrap">
                    <div className="flex items-center gap-2">
                        <span className="text-[16px] font-black text-slate-900 tracking-tight leading-none capitalize">{text}</span>
                        <div className="px-1.5 py-0.5 rounded-md bg-teal-50 text-[9px] font-black text-teal-600 uppercase border border-teal-100/50">Vetted</div>
                    </div>
                    <div className="flex items-center gap-2 opacity-50 text-[10px] font-black uppercase tracking-widest">
                       <span className="text-slate-400">UUID: </span>
                       <span className="text-slate-900">{record._id.slice(-12).toUpperCase()}</span>
                    </div>
                </div>
            ),
        },
        {
            title: () => (
                <div className="flex flex-col gap-1 w-full whitespace-nowrap">
                    <span className="text-[10px] font-black tracking-widest text-slate-400 uppercase">Diagnostic</span>
                    <span className="text-[11px] font-black text-slate-900 border-b-2 border-teal-500 pb-1 w-fit">INDICATOR MATRIX</span>
                </div>
            ),
            dataIndex: "keySymptoms",
            width: 280,
            render: (symptoms) => (
                <div className="flex flex-wrap gap-2 max-w-[320px]">
                    {symptoms.slice(0, 4).map((s, i) => (
                        <div key={i} className="flex items-center gap-1.5 px-2.5 py-1 bg-slate-50 border border-slate-100 rounded-lg whitespace-nowrap">
                             <div className="w-1.5 h-1.5 rounded-full bg-teal-500" />
                             <span className="text-[10px] font-black text-slate-600 uppercase tracking-tight">{s}</span>
                        </div>
                    ))}
                    {symptoms.length > 4 && (
                        <div className="px-2.5 py-1 bg-slate-100 border border-slate-200 rounded-lg border-dashed whitespace-nowrap">
                             <span className="text-[10px] font-black text-slate-400">+{symptoms.length - 4} More</span>
                        </div>
                    )}
                </div>
            ),
        },
        {
            title: () => (
                <div className="flex flex-col gap-1 w-full whitespace-nowrap">
                    <span className="text-[10px] font-black tracking-widest text-slate-400 uppercase">Network</span>
                    <span className="text-[11px] font-black text-slate-900 border-b-2 border-teal-500 pb-1 w-fit">FULFILLMENT</span>
                </div>
            ),
            dataIndex: "products",
            width: 160,
            render: (products) => (
                <div className="flex flex-col gap-3">
                    <div className="flex items-center gap-2">
                        <div className="w-8 h-8 rounded-lg bg-teal-100 text-teal-700 flex items-center justify-center border border-teal-200 shadow-sm">
                             <ShoppingBag size={14} strokeWidth={3} />
                        </div>
                        <span className="text-[13px] font-black text-slate-900">{products?.length || 0} <span className="text-slate-400 font-bold ml-0.5 uppercase text-[10px] tracking-widest">Nodes</span></span>
                    </div>
                    <div className="w-24 h-1 bg-slate-100 rounded-full overflow-hidden">
                        <div className="h-full bg-teal-500 rounded-full" style={{ width: `${Math.min((products?.length || 0) * 20, 100)}%` }} />
                    </div>
                </div>
            ),
        },
        {
            title: () => (
                <div className="flex flex-col gap-1 w-full whitespace-nowrap">
                    <span className="text-[10px] font-black tracking-widest text-slate-400 uppercase">History</span>
                    <span className="text-[11px] font-black text-slate-900 border-b-2 border-teal-500 pb-1 w-fit">SYNC TIMESTAMP</span>
                </div>
            ),
            dataIndex: "updatedAt",
            width: 180,
            render: (date) => (
                <div className="flex items-center gap-3">
                    <div className="flex flex-col">
                        <span className="text-[14px] font-black text-slate-900 leading-none">{new Date(date).toLocaleDateString()}</span>
                        <span className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] mt-2">v{date.slice(-2)} Revision</span>
                    </div>
                </div>
            ),
        },
        {
            title: () => (
                <div className="flex flex-col gap-1 w-full whitespace-nowrap">
                    <span className="text-[10px] font-black tracking-widest text-slate-400 uppercase">Central</span>
                    <span className="text-[11px] font-black text-slate-900 border-b-2 border-teal-500 pb-1 w-fit">COMMAND</span>
                </div>
            ),
            key: "action",
            width: 120,
            render: (_, record) => (
                <div className="flex items-center gap-3">
                    <Link to={`/superAdmin/edit-health-advice/${record._id}`}>
                        <Button
                            type="text"
                            icon={<Edit3 size={18} strokeWidth={2.5} />}
                            className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-all border border-slate-100 shadow-sm hover:shadow-lg hover:border-blue-200"
                        />
                    </Link>
                    <Button
                        type="text"
                        icon={<Trash2 size={18} strokeWidth={2.5} />}
                        onClick={() => handleDelete(record._id)}
                        className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white text-slate-400 hover:text-rose-600 hover:bg-rose-50 transition-all border border-slate-100 shadow-sm hover:shadow-lg hover:border-rose-200"
                    />
                </div>
            ),
        },
    ];

    const filteredData = healthAdvices.filter(item => 
        item.conditionName.toLowerCase().includes(searchText.toLowerCase())
    );

    return (
        <div className="space-y-12 pb-20 animate-in fade-in slide-in-from-bottom-6 duration-700 relative z-10">
            {/* Command Header */}
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8">
                <div className="space-y-2">
                    <div className="flex items-center gap-3 mb-2">
                        <div className="w-1.5 h-1.5 rounded-full bg-teal-600 animate-pulse" />
                        <span className="text-[11px] font-black text-teal-600 uppercase tracking-[0.3em]">Knowledge Base</span>
                    </div>
                    <h1 className="text-[42px] font-black text-slate-900 tracking-tighter leading-none">
                        Pulse <span className="text-teal-600">Protocol</span>
                    </h1>
                    <p className="text-[16px] text-slate-400 font-bold max-w-xl italic">
                        Managing clinical condition guides and expert lifestyle interventions.
                    </p>
                </div>
                
                <div className="flex items-center gap-4 w-full lg:w-auto">
                    <div className="relative flex-1 lg:w-80 shadow-2xl shadow-slate-200/50 rounded-[22px]">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                        <Input
                            placeholder="Find condition or indicator..."
                            className="h-14 pl-12 pr-6 bg-white border-none rounded-[22px] text-[15px] font-bold"
                            onChange={(e) => setSearchText(e.target.value)}
                        />
                    </div>
                    <Link to="/superAdmin/add-health-advice">
                        <button
                            className="h-14 px-8 flex items-center gap-2 justify-center rounded-[22px] bg-slate-900 border-none text-white font-black uppercase text-[12px] tracking-widest hover:scale-105 hover:bg-slate-800 transition-all shadow-xl shadow-slate-900/20 cursor-pointer"
                        >
                            <Plus size={18} /> New Condition
                        </button>
                    </Link>
                </div>
            </div>

            <div className="enterprise-card border-none shadow-2xl shadow-slate-200/50 overflow-hidden">
                <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-white">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-[18px] bg-teal-600 text-white flex items-center justify-center shadow-lg">
                            <ShieldCheck size={24} />
                        </div>
                        <div>
                            <h3 className="text-[18px] font-black text-slate-900 leading-none uppercase tracking-tighter">Medical Encyclopedia</h3>
                            <p className="text-[13px] text-slate-400 font-bold mt-1 uppercase tracking-widest italic">{healthAdvices.length} Active Protocols Synchronized</p>
                        </div>
                    </div>
                </div>

                <Table
                    columns={columns}
                    dataSource={filteredData}
                    rowKey="_id"
                    pagination={{ pageSize: 10, className: "px-10 py-6 font-black" }}
                    className="super-modern-table"
                    loading={isLoading}
                    scroll={{ x: 1100 }}
                />
            </div>

            <style>{`
                .super-modern-table .ant-table {
                    background: transparent !important;
                }
                .super-modern-table .ant-table-thead > tr > th {
                    background: #fdfdfe !important;
                    padding: 24px 24px !important;
                    border-bottom: 2px solid #f1f5f9 !important;
                }
                .super-modern-table .ant-table-tbody > tr > td {
                    padding: 24px 24px !important;
                    border-bottom: 1px solid #f8fafc !important;
                    color: #1e293b !important;
                    transition: all 0.3s ease !important;
                }
                .super-modern-table .ant-table-row {
                    cursor: pointer;
                }
                .super-modern-table .ant-table-row:hover > td {
                    background: #f8fafc !important;
                }
                .super-modern-table .ant-table-pagination.ant-pagination {
                    margin: 32px 40px !important;
                }
            `}</style>
        </div>
    );
};

export default HealthAdviceList;
